SELECT 
FROM quality_evaluation_events
WHERE plan_id = #{planId}
ORDER BY created_at DESC, id DESC
LIMIT #{limit}

SELECT 
FROM quality_evaluation_events



ORDER BY created_at DESC, id DESC
OFFSET #{offset}
LIMIT #{limit}

SELECT COALESCE(experiment_key, 'quality-validation-default') AS experiment_key, COALESCE(experiment_variant, 'UNKNOWN') AS experiment_variant, COUNT(1) AS total_count, SUM(CASE WHEN is_pass = TRUE THEN 1 ELSE 0 END) AS pass_count, AVG(score) AS avg_score, MAX(created_at) AS last_evaluated_at FROM quality_evaluation_events
AND plan_id = #{planId}
AND LOWER(COALESCE(experiment_key, '')) = LOWER(#{experimentKey})
AND LOWER(COALESCE(evaluator_type, '')) = LOWER(#{evaluatorType})
GROUP BY COALESCE(experiment_key, 'quality-validation-default'), COALESCE(experiment_variant, 'UNKNOWN') ORDER BY MAX(created_at) DESC LIMIT #{limit}
